content.problemStatement:
what is the output of the following code ?
```cpp
#include 
using namespace std;

int main() {
    int n = 5;
    int row = 1;
    while (row <= n) {
        int spaces = 1;
        while (spaces <= n - row) {
            cout << " ";  // Print spaces
            spaces++;
        }
        int stars = 1;
        while (stars <= (2 * row - 1)) {
            cout << "*";  // Print stars
            stars++;
        }
        cout << endl;
        row++;
    }
    return 0;
}
```

